1029 // match variations of a^2 + 2*a*b + b^2
1030 //
1031 // to reuse the code between the FP and Int versions, the instruction OpCodes
1032 //  and constant types have been turned into template parameters.
1033 //
1034 // Mul2Rhs: The constant to perform the multiplicative equivalent of X*2 with;
1035 //  should be `m_SpecificFP(2.0)` for FP and `m_SpecificInt(1)` for Int
1036 //  (we're matching `X<<1` instead of `X*2` for Int)
1037 template <bool FP, typename Mul2Rhs>
1038 static bool matchesSquareSum(BinaryOperator &I, Mul2Rhs M2Rhs, Value *&A,
1039                              Value *&B) {
1040   constexpr unsigned MulOp = FP ? Instruction::FMul : Instruction::Mul;
1041   constexpr unsigned AddOp = FP ? Instruction::FAdd : Instruction::Add;
1042   constexpr unsigned Mul2Op = FP ? Instruction::FMul : Instruction::Shl;
1043 
1044   // (a * a) + (((a * 2) + b) * b)
1045   if (match(&I, m_c_BinOp(
1046                     AddOp, m_OneUse(m_BinOp(MulOp, m_Value(A), m_Deferred(A))),
1047                     m_OneUse(m_c_BinOp(
1048                         MulOp,
1049                         m_c_BinOp(AddOp, m_BinOp(Mul2Op, m_Deferred(A), M2Rhs),
1050                                   m_Value(B)),
1051                         m_Deferred(B))))))
1052     return true;
1053 
1054   // ((a * b) * 2)  or ((a * 2) * b)
1055   // +
1056   // (a * a + b * b) or (b * b + a * a)
1057   return match(
1058       &I, m_c_BinOp(
1059               AddOp,
1060               m_CombineOr(
1061                   m_OneUse(m_BinOp(
1062                       Mul2Op, m_BinOp(MulOp, m_Value(A), m_Value(B)), M2Rhs)),
1063                   m_OneUse(m_c_BinOp(MulOp, m_BinOp(Mul2Op, m_Value(A), M2Rhs),
1064                                      m_Value(B)))),
1065               m_OneUse(
1066                   m_c_BinOp(AddOp, m_BinOp(MulOp, m_Deferred(A), m_Deferred(A)),
1067                             m_BinOp(MulOp, m_Deferred(B), m_Deferred(B))))));
1068 }
