1974 /// Eliminate an op from a linear interpolation (lerp) pattern.
1975 static Instruction *factorizeLerp(BinaryOperator &I,
1976                                   InstCombiner::BuilderTy &Builder) {
1977   Value *X, *Y, *Z;
1978   if (!match(&I, m_c_FAdd(m_OneUse(m_c_FMul(m_Value(Y),
1979                                             m_OneUse(m_FSub(m_FPOne(),
1980                                                             m_Value(Z))))),
1981                           m_OneUse(m_c_FMul(m_Value(X), m_Deferred(Z))))))
1982     return nullptr;
1983 
1984   // (Y * (1.0 - Z)) + (X * Z) --> Y + Z * (X - Y) [8 commuted variants]
1985   Value *XY = Builder.CreateFSubFMF(X, Y, &I);
1986   Value *MulZ = Builder.CreateFMulFMF(Z, XY, &I);
1987   return BinaryOperator::CreateFAddFMF(Y, MulZ, &I);
1988 }
