1990 /// Factor a common operand out of fadd/fsub of fmul/fdiv.
1991 static Instruction *factorizeFAddFSub(BinaryOperator &I,
1992                                       InstCombiner::BuilderTy &Builder) {
1993   assert((I.getOpcode() == Instruction::FAdd ||
1994           I.getOpcode() == Instruction::FSub) && "Expecting fadd/fsub");
1995   assert(I.hasAllowReassoc() && I.hasNoSignedZeros() &&
1996          "FP factorization requires FMF");
1997 
1998   if (Instruction *Lerp = factorizeLerp(I, Builder))
1999     return Lerp;
2000 
2001   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);
2002   if (!Op0->hasOneUse() || !Op1->hasOneUse())
2003     return nullptr;
2004 
2005   Value *X, *Y, *Z;
2006   bool IsFMul;
2007   if ((match(Op0, m_FMul(m_Value(X), m_Value(Z))) &&
2008        match(Op1, m_c_FMul(m_Value(Y), m_Specific(Z)))) ||
2009       (match(Op0, m_FMul(m_Value(Z), m_Value(X))) &&
2010        match(Op1, m_c_FMul(m_Value(Y), m_Specific(Z)))))
2011     IsFMul = true;
2012   else if (match(Op0, m_FDiv(m_Value(X), m_Value(Z))) &&
2013            match(Op1, m_FDiv(m_Value(Y), m_Specific(Z))))
2014     IsFMul = false;
2015   else
2016     return nullptr;
2017 
2018   // (X * Z) + (Y * Z) --> (X + Y) * Z
2019   // (X * Z) - (Y * Z) --> (X - Y) * Z
2020   // (X / Z) + (Y / Z) --> (X + Y) / Z
2021   // (X / Z) - (Y / Z) --> (X - Y) / Z
2022   bool IsFAdd = I.getOpcode() == Instruction::FAdd;
2023   Value *XY = IsFAdd ? Builder.CreateFAddFMF(X, Y, &I)
2024                      : Builder.CreateFSubFMF(X, Y, &I);
2025 
2026   // Bail out if we just created a denormal constant.
2027   // TODO: This is copied from a previous implementation. Is it necessary?
2028   const APFloat *C;
2029   if (match(XY, m_APFloat(C)) && !C->isNormal())
2030     return nullptr;
2031 
2032   return IsFMul ? BinaryOperator::CreateFMulFMF(XY, Z, &I)
2033                 : BinaryOperator::CreateFDivFMF(XY, Z, &I);
2034 }
